@props(['name' => 'icon', 'value' => ''])

<div x-data="iconPicker('{{ $value }}')" class="relative">
    <label class="block text-sm font-medium text-gray-700 mb-1">Service Icon</label>
    <input type="hidden" :name="fieldName" :value="selected">
    
    {{-- Selected Preview --}}
    <div class="flex items-center gap-3 mb-2">
        <div class="w-12 h-12 rounded-xl bg-indigo-50 border-2 border-indigo-200 flex items-center justify-center">
            <template x-if="selected">
                <svg class="w-6 h-6 text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" x-html="getPath(selected)"></svg>
            </template>
            <template x-if="!selected">
                <span class="text-xs text-gray-400">None</span>
            </template>
        </div>
        <div>
            <span class="text-sm text-gray-600" x-text="selected || 'No icon selected'"></span>
            <button type="button" x-show="selected" @click="selected = ''" class="block text-xs text-red-500 hover:text-red-700">Remove</button>
        </div>
    </div>

    {{-- Picker Toggle --}}
    <button type="button" @click="open = !open" class="w-full flex items-center justify-between px-4 py-2.5 bg-white border border-gray-300 rounded-lg shadow-sm hover:bg-gray-50 text-sm">
        <span class="text-gray-700">Choose an icon...</span>
        <svg class="w-4 h-4 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 9l-7 7-7-7"/></svg>
    </button>

    {{-- Picker Dropdown --}}
    <div x-show="open" x-cloak @click.outside="open = false" x-transition
         class="absolute z-50 mt-2 w-full bg-white rounded-xl shadow-2xl border border-gray-200 p-4" style="max-height: 420px;">
        
        {{-- Search --}}
        <input type="text" x-model="search" placeholder="Search icons..." 
               class="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-indigo-500 focus:border-indigo-500 mb-3">

        {{-- Icon Grid --}}
        <div class="overflow-y-auto grid grid-cols-8 gap-1" style="max-height: 320px;">
            <template x-for="icon in filteredIcons" :key="icon.name">
                <button type="button" @click="selectIcon(icon.name)"
                        :class="selected === icon.name ? 'bg-indigo-100 ring-2 ring-indigo-500' : 'hover:bg-gray-100'"
                        class="p-2 rounded-lg flex items-center justify-center transition-all" :title="icon.name">
                    <svg class="w-5 h-5 text-gray-700" fill="none" viewBox="0 0 24 24" stroke="currentColor" x-html="icon.path"></svg>
                </button>
            </template>
        </div>
    </div>
</div>

