        get filteredIcons() {
            if (!this.search) return this.icons;
            return this.icons.filter(i => i.name.includes(this.search.toLowerCase()));
        },
        selectIcon(name) {
            this.selected = name;
            this.open = false;
            this.search = '';
        },
        getPath(name) {
            const icon = this.icons.find(i => i.name === name);
            return icon ? icon.path : '';
        }
    }));
});
</script>
